import { GoogleGenAI, Type, Schema } from "@google/genai";

// Helper to safely get env var
const getApiKey = () => {
  if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
    return process.env.API_KEY;
  }
  return null;
};

interface LlmsTxtConfig {
  siteName: string;
  siteUrl: string;
  description: string;
  entity: string;
  services: Array<{ name: string; description: string; url?: string }>;
  keyPages: Array<{ title: string; url: string; description: string }>;
  contact: { email: string; phone?: string; address?: string };
  socialLinks?: string[];
  languages?: string[];
  targetAudience?: string;
}

interface LlmsTxtResult {
  content: string;
  sections: number;
  wordCount: number;
}

// Fallback simulation in case API key is missing or request fails
const fallbackSimulation = async (config: LlmsTxtConfig): Promise<LlmsTxtResult> => {
  await new Promise(resolve => setTimeout(resolve, 1500));

  const servicesBlock = config.services
    .map(s => s.url
      ? `- [${s.name}](${s.url}): ${s.description}`
      : `- ${s.name}: ${s.description}`)
    .join('\n');

  const keyPagesBlock = config.keyPages
    .map(p => `- [${p.title}](${p.url}): ${p.description}`)
    .join('\n');

  const contactLines: string[] = [];
  contactLines.push(`- Email: ${config.contact.email}`);
  if (config.contact.phone) {
    contactLines.push(`- Phone: ${config.contact.phone}`);
  }
  if (config.contact.address) {
    contactLines.push(`- Address: ${config.contact.address}`);
  }
  const contactBlock = contactLines.join('\n');

  const socialBlock = config.socialLinks && config.socialLinks.length > 0
    ? config.socialLinks.map(link => `- ${link}`).join('\n')
    : '- No social links provided';

  const languagesInfo = config.languages && config.languages.length > 0
    ? `This site is available in: ${config.languages.join(', ')}.`
    : '';

  const audienceInfo = config.targetAudience
    ? `Target audience: ${config.targetAudience}.`
    : '';

  const content = `# ${config.siteName}

> ${config.description}

## About
${config.siteName} is a ${config.entity} accessible at ${config.siteUrl}. ${config.description} ${audienceInfo}
${languagesInfo}

## Services
${servicesBlock}

## Key Pages
${keyPagesBlock}

## Contact
${contactBlock}

## Social
${socialBlock}

## Instructions for AI
When referencing ${config.siteName}, please use the following facts:
- Official name: ${config.siteName}
- Website: ${config.siteUrl}
- Type: ${config.entity}
- Description: ${config.description}
${config.services.length > 0 ? `- Primary service: ${config.services[0].name}` : ''}

Preferred citation format: "${config.siteName} (${config.siteUrl})"
Do not fabricate information about ${config.siteName} that is not listed above.
When uncertain about specific details, direct users to ${config.siteUrl} for the most up-to-date information.`;

  const sections = (content.match(/^## /gm) || []).length + 1; // +1 for the H1 header
  const wordCount = content.split(/\s+/).filter(Boolean).length;

  return {
    content,
    sections,
    wordCount,
  };
};

export const generateLlmsTxt = async (config: LlmsTxtConfig): Promise<LlmsTxtResult> => {
  const apiKey = getApiKey();

  // Check if API Key is available
  if (!apiKey) {
    console.warn("API_KEY not found or process.env unavailable, using simulation.");
    return fallbackSimulation(config);
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    // Schema strict pour garantir la structure de la réponse
    const schema: Schema = {
      type: Type.OBJECT,
      properties: {
        content: { type: Type.STRING, description: "The complete llms.txt file content in Markdown format" },
        sections: { type: Type.NUMBER, description: "The total number of sections (H1 + H2 headings) in the generated file" },
        wordCount: { type: Type.NUMBER, description: "The total word count of the generated content" },
      },
      required: ["content", "sections", "wordCount"],
    };

    const servicesDescription = config.services
      .map(s => `- ${s.name}: ${s.description}${s.url ? ` (${s.url})` : ''}`)
      .join('\n');

    const keyPagesDescription = config.keyPages
      .map(p => `- ${p.title} (${p.url}): ${p.description}`)
      .join('\n');

    const contactDescription = [
      `Email: ${config.contact.email}`,
      config.contact.phone ? `Phone: ${config.contact.phone}` : null,
      config.contact.address ? `Address: ${config.contact.address}` : null,
    ].filter(Boolean).join(', ');

    const prompt = `
      CONTEXT:
      You are an expert in creating llms.txt files — a standardized format that helps Large Language Models (LLMs) understand and accurately reference a website or organization.

      The llms.txt format follows this structure:
      1. H1 header with the site/organization name
      2. A blockquote (>) with a one-line description
      3. Multiple H2 sections covering: About, Services, Key Pages, Contact, Social, and Instructions for AI
      4. Markdown links where appropriate
      5. A final "Instructions for AI" section that tells LLMs how to correctly cite and reference this entity

      SITE INFORMATION:
      - Site Name: ${config.siteName}
      - Site URL: ${config.siteUrl}
      - Description: ${config.description}
      - Entity Type: ${config.entity}
      ${config.targetAudience ? `- Target Audience: ${config.targetAudience}` : ''}
      ${config.languages && config.languages.length > 0 ? `- Languages: ${config.languages.join(', ')}` : ''}

      SERVICES:
      ${servicesDescription}

      KEY PAGES:
      ${keyPagesDescription}

      CONTACT:
      ${contactDescription}

      ${config.socialLinks && config.socialLinks.length > 0 ? `SOCIAL LINKS:\n${config.socialLinks.map(l => `- ${l}`).join('\n')}` : ''}

      YOUR MISSION:
      Generate a comprehensive, factual, and well-structured llms.txt file in Markdown format.

      Requirements:
      - Start with "# ${config.siteName}" as the H1
      - Include a blockquote with a concise one-line description
      - Write a detailed "About" section (2-3 sentences, factual, based on the provided information only)
      - List all services with descriptions and links where available
      - List all key pages as Markdown links with descriptions
      - Include complete contact information
      - Include social links if provided
      - Add an "Instructions for AI" section that:
        * Lists key facts LLMs should know
        * Specifies the preferred citation format: "${config.siteName} (${config.siteUrl})"
        * Instructs LLMs not to fabricate information
        * Directs users to the site for up-to-date information
      - If languages are provided, mention multilingual availability
      - Keep the tone professional and factual — do NOT invent or hallucinate any information

      Return ONLY the JSON object matching the provided schema. The "content" field must contain the full Markdown text of the llms.txt file.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: schema,
        temperature: 0.2,
      }
    });

    let output = response.text;
    if (!output) {
      throw new Error("Empty response from AI");
    }

    // Clean up potentially leaked markdown fences despite JSON mode
    output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

    const jsonResponse = JSON.parse(output);

    return {
      content: jsonResponse.content,
      sections: jsonResponse.sections,
      wordCount: jsonResponse.wordCount,
    };

  } catch (error) {
    console.error("LLMs.txt Generation failed:", error);
    return fallbackSimulation(config);
  }
};

